import { useState } from 'react';
import { Link } from 'react-router-dom';
import { useSettings } from '@/lib/store';
import { getProvider, isProviderConfigured } from '@/lib/ai/factory';
import { appendSession, newId } from '@/lib/storage';
import type { ParaphraseFeedback, ParaphraseSession } from '@/lib/schema';
import { ParaphraseFeedbackPanel } from '@/components/ParaphraseFeedbackPanel';
import { createLogger } from '@/lib/logger';

const log = createLogger('paraphrase');

export function ParaphraseMode() {
  const settings = useSettings((s) => s.settings);
  const configured = isProviderConfigured(settings);

  const [source, setSource] = useState('');
  const [sourceLoading, setSourceLoading] = useState(false);
  const [sourceError, setSourceError] = useState<string | null>(null);

  const [rewrites, setRewrites] = useState<string[]>(['', '', '']);
  const [feedback, setFeedback] = useState<ParaphraseFeedback | null>(null);
  const [feedbackLoading, setFeedbackLoading] = useState(false);
  const [feedbackError, setFeedbackError] = useState<string | null>(null);
  const [savedId, setSavedId] = useState<string | null>(null);

  async function fetchSource() {
    if (!configured) {
      setSourceError('Set the API key in Settings first.');
      return;
    }
    setSourceLoading(true);
    setSourceError(null);
    try {
      const provider = getProvider(settings);
      const s = await provider.generateParaphraseSource(settings.prefs);
      setSource(s);
      setRewrites(['', '', '']);
      setFeedback(null);
      setFeedbackError(null);
      setSavedId(null);
    } catch (err) {
      setSourceError(err instanceof Error ? err.message : String(err));
    } finally {
      setSourceLoading(false);
    }
  }

  function setRewrite(i: number, value: string) {
    setRewrites((prev) => {
      const next = [...prev];
      next[i] = value;
      return next;
    });
  }

  const allFilled = rewrites.every((r) => r.trim().length > 0);

  async function handleSubmit() {
    if (!source.trim() || !allFilled) return;
    log.debug('submit', { sourceLen: source.length, rewriteLens: rewrites.map((r) => r.length) });
    setFeedbackLoading(true);
    setFeedbackError(null);
    try {
      const provider = getProvider(settings);
      const fb = await provider.paraphraseFeedback({
        source,
        rewrites: rewrites.map((r) => r.trim()),
      });
      log.debug('feedback received', {
        diversity: fb.diversity_score,
        fidelities: fb.per_rewrite.map((p) => p.fidelity),
      });
      setFeedback(fb);

      const session: ParaphraseSession = {
        id: newId('paraphrase'),
        mode: 'paraphrase',
        created_at: new Date().toISOString(),
        source,
        rewrites: rewrites.map((r) => r.trim()) as [string, string, string],
        feedback: fb,
      };
      appendSession(session);
      log.debug('session saved', { id: session.id });
      setSavedId(session.id);
    } catch (err) {
      log.error('feedback failed', err);
      setFeedbackError(err instanceof Error ? err.message : String(err));
    } finally {
      setFeedbackLoading(false);
    }
  }

  function handleReset() {
    setSource('');
    setRewrites(['', '', '']);
    setFeedback(null);
    setFeedbackError(null);
    setSavedId(null);
  }

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-lg font-semibold">Paraphrasing drill</h2>
        <p className="text-sm text-zinc-500 mt-1">
          Rewrite the source sentence three different ways. AI will rate each on meaning fidelity, naturalness, and overall structural diversity.
        </p>
      </div>

      <section className="space-y-2">
        <div className="text-[10px] uppercase tracking-wide font-semibold text-zinc-500">Source sentence</div>
        <textarea
          value={source}
          onChange={(e) => setSource(e.target.value)}
          rows={2}
          placeholder="Click 'Generate sentence' or paste one yourself."
          className="w-full rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-950 p-2.5 text-sm leading-relaxed resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500"
        />
        <div className="flex flex-wrap gap-2 text-xs">
          <button
            type="button"
            onClick={fetchSource}
            disabled={sourceLoading || !configured}
            className="px-3 py-1.5 rounded-md bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 disabled:opacity-50"
          >
            {sourceLoading ? 'Generating…' : 'Generate sentence'}
          </button>
          {!configured && (
            <Link to="/settings" className="px-3 py-1.5 rounded-md border border-amber-300 text-amber-700 dark:text-amber-400">
              Set API key →
            </Link>
          )}
          {sourceError && (
            <span className="text-red-600 dark:text-red-400 self-center">{sourceError}</span>
          )}
        </div>
      </section>

      <section className="space-y-3">
        <div className="text-[10px] uppercase tracking-wide font-semibold text-zinc-500">
          Your three rewrites
        </div>
        {rewrites.map((r, i) => (
          <div key={i} className="space-y-1">
            <div className="text-[11px] font-semibold text-zinc-600 dark:text-zinc-400">
              Rewrite {i + 1}
            </div>
            <textarea
              value={r}
              onChange={(e) => setRewrite(i, e.target.value)}
              rows={2}
              disabled={!source.trim() || feedbackLoading}
              placeholder={`Aim for a structurally different version from rewrite ${i === 0 ? '2 and 3' : i === 1 ? '1 and 3' : '1 and 2'}.`}
              className="w-full rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-950 p-2.5 text-sm leading-relaxed resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-60"
            />
          </div>
        ))}
      </section>

      <div className="flex flex-wrap gap-2 items-center">
        <button
          type="button"
          onClick={handleSubmit}
          disabled={!allFilled || !source.trim() || feedbackLoading || !configured}
          className="px-4 py-2 rounded-md bg-indigo-600 text-white text-sm font-semibold disabled:opacity-50"
        >
          {feedbackLoading ? 'Evaluating…' : savedId ? 'Re-evaluate' : 'Submit for evaluation'}
        </button>
        {savedId && (
          <button
            type="button"
            onClick={handleReset}
            className="px-3 py-1.5 rounded-md border border-zinc-200 dark:border-zinc-800 text-xs"
          >
            Run another →
          </button>
        )}
        {feedbackError && (
          <span className="text-xs text-red-600 dark:text-red-400">{feedbackError}</span>
        )}
      </div>

      {feedback && <ParaphraseFeedbackPanel feedback={feedback} rewrites={rewrites} />}
    </div>
  );
}
