/**
 * Best-effort JSON parsing for AI replies. Models occasionally wrap output in
 * markdown fences or, in the case of reasoning models (DeepSeek-R1, o1-style),
 * prefix the answer with a <think>...</think> block. We strip both before
 * handing to JSON.parse so the user does not see avoidable parse errors.
 */
export function parseJsonLoose(raw: string): unknown {
  let text = raw.trim();

  // Strip leading reasoning blocks: <think>...</think>, <reasoning>...</reasoning>
  text = text.replace(/^<(think|reasoning)>[\s\S]*?<\/\1>\s*/i, '');

  // Strip ```json ... ``` (or plain ```) fences
  if (text.startsWith('```')) {
    text = text.replace(/^```(?:json)?\s*/i, '').replace(/```\s*$/i, '');
  }

  // If the model still emitted prose around the JSON, grab the first balanced
  // {...} or [...] block as a last resort.
  if (text[0] !== '{' && text[0] !== '[') {
    const objStart = text.indexOf('{');
    const arrStart = text.indexOf('[');
    const start =
      objStart === -1 ? arrStart : arrStart === -1 ? objStart : Math.min(objStart, arrStart);
    if (start !== -1) text = text.slice(start);
  }

  return JSON.parse(text);
}
