import type { Session } from './schema';

export interface SessionStats {
  total: number;
  thisWeek: number;
  writeCount: number;
  paraphraseCount: number;
  /** Number of consecutive days up to and including today with at least one session. */
  currentStreakDays: number;
  /** Longest consecutive-day streak ever (across all history). */
  longestStreakDays: number;
}

function dayKey(d: Date): string {
  // Use the user's local date so streak boundaries align with their lived day.
  return `${d.getFullYear()}-${(d.getMonth() + 1).toString().padStart(2, '0')}-${d
    .getDate()
    .toString()
    .padStart(2, '0')}`;
}

export function computeStats(sessions: Session[], now: Date = new Date()): SessionStats {
  const total = sessions.length;
  if (total === 0) {
    return {
      total: 0,
      thisWeek: 0,
      writeCount: 0,
      paraphraseCount: 0,
      currentStreakDays: 0,
      longestStreakDays: 0,
    };
  }

  const weekAgoMs = now.getTime() - 7 * 24 * 60 * 60 * 1000;
  let thisWeek = 0;
  let writeCount = 0;
  let paraphraseCount = 0;
  const dayWith = new Set<string>();

  for (const s of sessions) {
    const t = new Date(s.created_at);
    if (t.getTime() >= weekAgoMs) thisWeek += 1;
    if (s.mode === 'write') writeCount += 1;
    else paraphraseCount += 1;
    dayWith.add(dayKey(t));
  }

  // Current streak — walk back from today; if today has no session, allow yesterday as
  // the streak start (so opening the app at 00:01 doesn't reset the streak).
  let currentStreak = 0;
  const cursor = new Date(now);
  if (!dayWith.has(dayKey(cursor))) {
    cursor.setDate(cursor.getDate() - 1);
    if (!dayWith.has(dayKey(cursor))) {
      currentStreak = 0;
    } else {
      currentStreak = 1;
      cursor.setDate(cursor.getDate() - 1);
      while (dayWith.has(dayKey(cursor))) {
        currentStreak += 1;
        cursor.setDate(cursor.getDate() - 1);
      }
    }
  } else {
    currentStreak = 1;
    cursor.setDate(cursor.getDate() - 1);
    while (dayWith.has(dayKey(cursor))) {
      currentStreak += 1;
      cursor.setDate(cursor.getDate() - 1);
    }
  }

  // Longest streak — sort distinct day keys, scan for runs.
  const sortedDays = [...dayWith].sort();
  let longest = 0;
  let run = 0;
  let prev: Date | null = null;
  for (const k of sortedDays) {
    const [y, m, d] = k.split('-').map((n) => parseInt(n, 10));
    const date = new Date(y, m - 1, d);
    if (prev && (date.getTime() - prev.getTime()) === 24 * 60 * 60 * 1000) {
      run += 1;
    } else {
      run = 1;
    }
    if (run > longest) longest = run;
    prev = date;
  }

  return {
    total,
    thisWeek,
    writeCount,
    paraphraseCount,
    currentStreakDays: currentStreak,
    longestStreakDays: longest,
  };
}
