import {
  AiCallError,
  AiNotConfiguredError,
  resolveFeedbackModel,
  resolveTopicModel,
  type AiProvider,
  type TopicPrefs,
} from './provider';
import { createLogger, preview } from '../logger';

const log = createLogger('anthropic');
import {
  PARAPHRASE_FEEDBACK_SYSTEM,
  TOPIC_PARAPHRASE_SYSTEM,
  TOPIC_WRITING_SYSTEM,
  WRITING_FEEDBACK_SYSTEM,
  paraphraseFeedbackUserMessage,
  topicParaphraseUserMessage,
  topicWritingUserMessage,
  writingFeedbackUserMessage,
} from './prompts';
import {
  ParaphraseFeedbackSchema,
  WritingFeedbackSchema,
  type ParaphraseFeedback,
  type Settings,
  type WritingFeedback,
} from '../schema';
import { parseJsonLoose } from './json';

interface MsgArgs {
  model: string;
  system: string;
  user: string;
  temperature?: number;
}

export class AnthropicProvider implements AiProvider {
  readonly id = 'anthropic' as const;
  private apiKey: string;
  private settings: Settings;

  constructor(settings: Settings) {
    this.settings = settings;
    this.apiKey = settings.anthropic_api_key.trim();
  }

  private async message({ model, system, user, temperature = 0.8 }: MsgArgs): Promise<string> {
    if (!this.apiKey) throw new AiNotConfiguredError('Anthropic');
    const body = {
      model,
      max_tokens: 1024,
      temperature,
      system,
      messages: [{ role: 'user', content: user }],
    };

    log.debug('message →', { model, userLen: user.length, userPreview: preview(user) });
    const t0 = performance.now();

    let response: Response;
    try {
      response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': this.apiKey,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify(body),
      });
    } catch (err) {
      log.error('network error', err);
      throw new AiCallError(
        `Network error calling Anthropic: ${err instanceof Error ? err.message : String(err)}`
      );
    }
    if (!response.ok) {
      const text = await response.text().catch(() => '');
      log.error('http error', { status: response.status, body: text.slice(0, 200) });
      throw new AiCallError(
        `Anthropic ${response.status}: ${text.slice(0, 200)}`,
        response.status
      );
    }
    const data = (await response.json()) as {
      content?: Array<{ type: string; text?: string }>;
      usage?: { input_tokens?: number; output_tokens?: number };
    };
    const text = data.content?.find((b) => b.type === 'text')?.text?.trim() ?? '';
    log.debug('message ←', {
      durationMs: Math.round(performance.now() - t0),
      contentLen: text.length,
      contentPreview: preview(text),
      tokens: data.usage,
    });
    if (!text) throw new AiCallError('Anthropic returned empty content');
    return text;
  }

  async generateWritingTopic(prefs: TopicPrefs): Promise<string> {
    return this.message({
      model: resolveTopicModel(this.settings),
      system: TOPIC_WRITING_SYSTEM,
      user: topicWritingUserMessage(prefs),
    });
  }

  async generateParaphraseSource(prefs: TopicPrefs): Promise<string> {
    return this.message({
      model: resolveTopicModel(this.settings),
      system: TOPIC_PARAPHRASE_SYSTEM,
      user: topicParaphraseUserMessage(prefs),
    });
  }

  async writingFeedback(args: { topic: string; draft: string; revised: string }): Promise<WritingFeedback> {
    const raw = await this.message({
      model: resolveFeedbackModel(this.settings),
      system: WRITING_FEEDBACK_SYSTEM,
      user: writingFeedbackUserMessage(args),
      temperature: 0.4,
    });
    return WritingFeedbackSchema.parse(parseJsonLoose(raw));
  }

  async paraphraseFeedback(args: { source: string; rewrites: string[] }): Promise<ParaphraseFeedback> {
    const raw = await this.message({
      model: resolveFeedbackModel(this.settings),
      system: PARAPHRASE_FEEDBACK_SYSTEM,
      user: paraphraseFeedbackUserMessage(args),
      temperature: 0.4,
    });
    return ParaphraseFeedbackSchema.parse(parseJsonLoose(raw));
  }
}
