import { useState } from 'react';
import type { ParaphraseFeedback } from '@/lib/schema';

interface Props {
  feedback: ParaphraseFeedback;
  rewrites: string[];
}

const FIDELITY_LABEL: Record<'ok' | 'partial' | 'broken', { tag: string; tone: string }> = {
  ok: { tag: '✓ meaning preserved', tone: 'bg-emerald-50 text-emerald-700 dark:bg-emerald-900/30 dark:text-emerald-300 border-emerald-200 dark:border-emerald-800' },
  partial: { tag: '⚠ drifted', tone: 'bg-amber-50 text-amber-700 dark:bg-amber-900/30 dark:text-amber-300 border-amber-200 dark:border-amber-800' },
  broken: { tag: '✗ meaning changed', tone: 'bg-red-50 text-red-700 dark:bg-red-900/30 dark:text-red-300 border-red-200 dark:border-red-800' },
};

export function ParaphraseFeedbackPanel({ feedback, rewrites }: Props) {
  const [showRefs, setShowRefs] = useState(false);

  return (
    <div className="space-y-4 rounded-lg border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 p-4">
      <div className="flex items-center justify-between">
        <h3 className="text-sm font-semibold flex items-center gap-2">
          <span className="text-[10px] uppercase tracking-wider bg-indigo-100 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300 px-1.5 py-0.5 rounded">
            AI evaluation
          </span>
        </h3>
        <DiversityBadge score={feedback.diversity_score} />
      </div>

      {feedback.overall && (
        <p className="text-sm text-zinc-700 dark:text-zinc-300 leading-relaxed">
          {feedback.overall}
        </p>
      )}

      <ul className="space-y-3">
        {feedback.per_rewrite.map((item, i) => {
          const lbl = FIDELITY_LABEL[item.fidelity];
          return (
            <li key={i} className="space-y-1.5">
              <div className="flex items-center gap-2 flex-wrap">
                <span className="text-[10px] uppercase font-semibold text-zinc-500">
                  Rewrite {i + 1}
                </span>
                <span className={`text-[10px] font-semibold px-1.5 py-0.5 rounded border ${lbl.tone}`}>
                  {lbl.tag}
                </span>
                <NaturalnessBar score={item.naturalness} />
              </div>
              <div className="text-sm rounded-md bg-zinc-50 dark:bg-zinc-950 border border-zinc-200 dark:border-zinc-800 p-2 italic">
                {rewrites[i] || <span className="text-zinc-400">(empty)</span>}
              </div>
              <div className="text-xs text-zinc-600 dark:text-zinc-400 leading-snug">
                {item.comment}
              </div>
            </li>
          );
        })}
      </ul>

      {feedback.reference_paraphrases.length > 0 && (
        <div className="space-y-2">
          <button
            type="button"
            onClick={() => setShowRefs((s) => !s)}
            className="text-xs text-indigo-600 dark:text-indigo-400 hover:underline"
          >
            {showRefs ? 'Hide' : 'Show'} AI's reference paraphrases ({feedback.reference_paraphrases.length})
          </button>
          {showRefs && (
            <ul className="space-y-1.5">
              {feedback.reference_paraphrases.map((r, i) => (
                <li
                  key={i}
                  className="text-sm rounded-md bg-indigo-50/60 dark:bg-indigo-500/5 border border-indigo-200 dark:border-indigo-500/30 p-2"
                >
                  {r}
                </li>
              ))}
            </ul>
          )}
        </div>
      )}
    </div>
  );
}

function NaturalnessBar({ score }: { score: number }) {
  return (
    <span className="inline-flex gap-0.5" aria-label={`naturalness ${score} of 5`}>
      {[1, 2, 3, 4, 5].map((i) => (
        <span
          key={i}
          className={`w-1.5 h-3 rounded-sm ${
            i <= score
              ? 'bg-indigo-500'
              : 'bg-zinc-200 dark:bg-zinc-700'
          }`}
        />
      ))}
    </span>
  );
}

function DiversityBadge({ score }: { score: number }) {
  const tone =
    score >= 4
      ? 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300'
      : score >= 3
        ? 'bg-amber-100 text-amber-700 dark:bg-amber-900/40 dark:text-amber-300'
        : 'bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-300';
  return (
    <span className={`text-[10px] uppercase font-semibold px-1.5 py-0.5 rounded ${tone}`}>
      Diversity {score}/5
    </span>
  );
}
