import { useEffect, useMemo, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { useSettings } from '@/lib/store';
import { getProvider, isProviderConfigured } from '@/lib/ai/factory';
import { useCountdown } from '@/lib/useCountdown';
import { TimeUpDialog, countWords } from '@/components/TimeUpDialog';
import { CountdownBar } from '@/components/CountdownBar';
import { WritingFeedbackPanel } from '@/components/WritingFeedbackPanel';
import { appendSession, newId, saveDraft, clearDraft, loadDraft } from '@/lib/storage';
import type { WriteSession, WritingFeedback } from '@/lib/schema';
import { createLogger } from '@/lib/logger';

const log = createLogger('write');

type Phase = 'setup' | 'stage1' | 'stage2' | 'done';

interface DraftState {
  topic: string;
  stage1_draft: string;
  stage1_extensions: number[];
  stage1_target_seconds: number;
  stage2_revision: string;
  stage2_extensions: number[];
  stage2_target_seconds: number;
}

export function WriteMode() {
  const settings = useSettings((s) => s.settings);
  const configured = isProviderConfigured(settings);

  const [phase, setPhase] = useState<Phase>('setup');
  const [topic, setTopic] = useState('');
  const [topicLoading, setTopicLoading] = useState(false);
  const [topicError, setTopicError] = useState<string | null>(null);

  const [stage1Draft, setStage1Draft] = useState('');
  const [stage1Extensions, setStage1Extensions] = useState<number[]>([]);
  const [stage1StartedAt, setStage1StartedAt] = useState<number>(0);
  const [stage1UsedSeconds, setStage1UsedSeconds] = useState<number>(0);

  const [revision, setRevision] = useState('');
  const [stage2Extensions, setStage2Extensions] = useState<number[]>([]);
  const [stage2StartedAt, setStage2StartedAt] = useState<number>(0);
  const [stage2UsedSeconds, setStage2UsedSeconds] = useState<number>(0);

  const [writingSeconds, setWritingSeconds] = useState(settings.prefs.writing_seconds);
  const [revisionSeconds, setRevisionSeconds] = useState(settings.prefs.revision_seconds);

  const [savedSessionId, setSavedSessionId] = useState<string | null>(null);
  const [feedback, setFeedback] = useState<WritingFeedback | null>(null);
  const [feedbackLoading, setFeedbackLoading] = useState(false);
  const [feedbackError, setFeedbackError] = useState<string | null>(null);

  const [showTimeUp, setShowTimeUp] = useState<'stage1' | 'stage2' | null>(null);
  const [resumePrompt, setResumePrompt] = useState<DraftState | null>(null);

  const countdown = useCountdown();
  const stage1TextareaRef = useRef<HTMLTextAreaElement | null>(null);
  const stage2TextareaRef = useRef<HTMLTextAreaElement | null>(null);

  // On mount: offer to resume an in-flight draft
  useEffect(() => {
    const draft = loadDraft();
    if (draft && draft.mode === 'write' && draft.data) {
      setResumePrompt(draft.data as DraftState);
    }
  }, []);

  // React when timer expires
  useEffect(() => {
    if (!countdown.expired) return;
    if (phase === 'stage1') setShowTimeUp('stage1');
    else if (phase === 'stage2') setShowTimeUp('stage2');
  }, [countdown.expired, phase]);

  // Auto-save draft state every state change while in stage1/stage2
  useEffect(() => {
    if (phase !== 'stage1' && phase !== 'stage2') return;
    const handle = setTimeout(() => {
      const data: DraftState = {
        topic,
        stage1_draft: stage1Draft,
        stage1_extensions: stage1Extensions,
        stage1_target_seconds: writingSeconds,
        stage2_revision: revision,
        stage2_extensions: stage2Extensions,
        stage2_target_seconds: revisionSeconds,
      };
      saveDraft({ mode: 'write', data, saved_at: new Date().toISOString() });
    }, 500);
    return () => clearTimeout(handle);
  }, [
    phase,
    topic,
    stage1Draft,
    stage1Extensions,
    revision,
    stage2Extensions,
    writingSeconds,
    revisionSeconds,
  ]);

  // Focus textarea when entering a stage
  useEffect(() => {
    if (phase === 'stage1' && !showTimeUp) stage1TextareaRef.current?.focus();
    if (phase === 'stage2' && !showTimeUp) stage2TextareaRef.current?.focus();
  }, [phase, showTimeUp]);

  async function fetchTopic() {
    if (!configured) {
      setTopicError('Set the API key in Settings first.');
      return;
    }
    setTopicLoading(true);
    setTopicError(null);
    try {
      const provider = getProvider(settings);
      const t = await provider.generateWritingTopic(settings.prefs);
      setTopic(t);
    } catch (err) {
      setTopicError(err instanceof Error ? err.message : String(err));
    } finally {
      setTopicLoading(false);
    }
  }

  function startStage1() {
    if (!topic.trim()) {
      setTopicError('Pick or paste a topic first.');
      return;
    }
    log.debug('stage1 start', { writingSeconds, topicLen: topic.length });
    setStage1Draft('');
    setStage1Extensions([]);
    setStage1StartedAt(Date.now());
    countdown.start(writingSeconds);
    setPhase('stage1');
  }

  function extendStage1(seconds: number) {
    log.debug('stage1 extend', { seconds });
    setStage1Extensions((e) => [...e, seconds]);
    countdown.addSeconds(seconds);
    setShowTimeUp(null);
  }

  function endStage1() {
    const used = Math.round((Date.now() - stage1StartedAt) / 1000);
    log.debug('stage1 end', { usedSeconds: used, words: countWords(stage1Draft), extensions: stage1Extensions });
    setStage1UsedSeconds(used);
    countdown.stop();
    setShowTimeUp(null);

    setRevision(stage1Draft);
    setStage2Extensions([]);
    setStage2StartedAt(Date.now());
    countdown.start(revisionSeconds);
    setPhase('stage2');
  }

  function extendStage2(seconds: number) {
    log.debug('stage2 extend', { seconds });
    setStage2Extensions((e) => [...e, seconds]);
    countdown.addSeconds(seconds);
    setShowTimeUp(null);
  }

  function endStage2() {
    const used = Math.round((Date.now() - stage2StartedAt) / 1000);
    setStage2UsedSeconds(used);
    countdown.stop();
    setShowTimeUp(null);

    const session: WriteSession = {
      id: newId('write'),
      mode: 'write',
      created_at: new Date().toISOString(),
      topic,
      stage1_draft: stage1Draft,
      stage1_target_seconds: writingSeconds,
      stage1_used_seconds: stage1UsedSeconds,
      stage1_extensions: stage1Extensions,
      stage2_revision: revision,
      stage2_target_seconds: revisionSeconds,
      stage2_used_seconds: used,
      stage2_extensions: stage2Extensions,
    };
    appendSession(session);
    clearDraft();
    log.debug('session saved', { id: session.id, draftWords: countWords(stage1Draft), revisionWords: countWords(revision) });
    setSavedSessionId(session.id);
    setPhase('done');
  }

  async function fetchFeedback() {
    if (!savedSessionId) return;
    log.debug('feedback request', { sessionId: savedSessionId });
    setFeedbackLoading(true);
    setFeedbackError(null);
    try {
      const provider = getProvider(settings);
      const fb = await provider.writingFeedback({
        topic,
        draft: stage1Draft,
        revised: revision,
      });
      log.debug('feedback received', {
        vocabSwaps: fb.vocab_swaps.length,
        structureUpgrades: fb.structure_upgrades.length,
        missingExpressions: fb.missing_expressions.length,
      });
      setFeedback(fb);
    } catch (err) {
      log.error('feedback failed', err);
      setFeedbackError(err instanceof Error ? err.message : String(err));
    } finally {
      setFeedbackLoading(false);
    }
  }

  function resetAll() {
    setPhase('setup');
    setTopic('');
    setStage1Draft('');
    setStage1Extensions([]);
    setStage1UsedSeconds(0);
    setRevision('');
    setStage2Extensions([]);
    setStage2UsedSeconds(0);
    setSavedSessionId(null);
    setFeedback(null);
    setFeedbackError(null);
    countdown.stop();
    setShowTimeUp(null);
    clearDraft();
  }

  const stage1Words = useMemo(() => countWords(stage1Draft), [stage1Draft]);
  const stage2Words = useMemo(() => countWords(revision), [revision]);

  if (resumePrompt) {
    return (
      <ResumeBanner
        draft={resumePrompt}
        onResume={() => {
          setTopic(resumePrompt.topic);
          setStage1Draft(resumePrompt.stage1_draft);
          setStage1Extensions(resumePrompt.stage1_extensions);
          setWritingSeconds(resumePrompt.stage1_target_seconds);
          setRevision(resumePrompt.stage2_revision);
          setStage2Extensions(resumePrompt.stage2_extensions);
          setRevisionSeconds(resumePrompt.stage2_target_seconds);
          setResumePrompt(null);
          // We don't auto-restart timers — let user choose where to pick up.
          // For MVP, dump them into setup with prefilled state.
        }}
        onDiscard={() => {
          clearDraft();
          setResumePrompt(null);
        }}
      />
    );
  }

  return (
    <div className="space-y-6">
      {phase === 'setup' && (
        <SetupPanel
          topic={topic}
          setTopic={setTopic}
          fetchTopic={fetchTopic}
          topicLoading={topicLoading}
          topicError={topicError}
          configured={configured}
          writingSeconds={writingSeconds}
          revisionSeconds={revisionSeconds}
          setWritingSeconds={setWritingSeconds}
          setRevisionSeconds={setRevisionSeconds}
          onStart={startStage1}
        />
      )}

      {phase === 'stage1' && (
        <StagePanel
          stage="stage1"
          topic={topic}
          totalSeconds={writingSeconds + stage1Extensions.reduce((a, b) => a + b, 0)}
          secondsLeft={countdown.secondsLeft}
          words={stage1Words}
          textareaRef={stage1TextareaRef}
          left={
            <textarea
              ref={stage1TextareaRef}
              value={stage1Draft}
              onChange={(e) => setStage1Draft(e.target.value)}
              className="w-full h-[55vh] rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-950 p-3 text-sm leading-relaxed resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500"
              placeholder="Just write. Don't stop to fix anything."
              disabled={!!showTimeUp}
            />
          }
          rightLabel={null}
          right={null}
          onForceStop={() => setShowTimeUp('stage1')}
        />
      )}

      {phase === 'stage2' && (
        <StagePanel
          stage="stage2"
          topic={topic}
          totalSeconds={revisionSeconds + stage2Extensions.reduce((a, b) => a + b, 0)}
          secondsLeft={countdown.secondsLeft}
          words={stage2Words}
          textareaRef={stage2TextareaRef}
          leftLabel="Original draft"
          left={
            <div className="w-full h-[55vh] rounded-md border border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-950 p-3 text-sm leading-relaxed overflow-y-auto whitespace-pre-wrap">
              {stage1Draft || <em className="text-zinc-400">empty</em>}
            </div>
          }
          rightLabel="Revision"
          right={
            <textarea
              ref={stage2TextareaRef}
              value={revision}
              onChange={(e) => setRevision(e.target.value)}
              className="w-full h-[55vh] rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-950 p-3 text-sm leading-relaxed resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500"
              placeholder="Tighten word choice, fix grammar, upgrade structures."
              disabled={!!showTimeUp}
            />
          }
          onForceStop={() => setShowTimeUp('stage2')}
        />
      )}

      {phase === 'done' && (
        <DonePanel
          topic={topic}
          stage1Draft={stage1Draft}
          revision={revision}
          stage1Words={stage1Words}
          stage2Words={stage2Words}
          stage1UsedSeconds={stage1UsedSeconds}
          stage2UsedSeconds={stage2UsedSeconds}
          stage1Extensions={stage1Extensions}
          stage2Extensions={stage2Extensions}
          configured={configured}
          feedback={feedback}
          feedbackLoading={feedbackLoading}
          feedbackError={feedbackError}
          onRequestFeedback={fetchFeedback}
          onReset={resetAll}
        />
      )}

      {showTimeUp === 'stage1' && (
        <TimeUpDialog
          stage="stage1"
          wordCount={stage1Words}
          onExtend={extendStage1}
          onCancel={endStage1}
        />
      )}
      {showTimeUp === 'stage2' && (
        <TimeUpDialog
          stage="stage2"
          wordCount={stage2Words}
          onExtend={extendStage2}
          onCancel={endStage2}
        />
      )}
    </div>
  );
}

interface StagePanelProps {
  stage: 'stage1' | 'stage2';
  topic: string;
  totalSeconds: number;
  secondsLeft: number;
  words: number;
  textareaRef: React.RefObject<HTMLTextAreaElement>;
  leftLabel?: string | null;
  left: React.ReactNode;
  rightLabel?: string | null;
  right: React.ReactNode;
  onForceStop: () => void;
}

function StagePanel({
  stage,
  topic,
  totalSeconds,
  secondsLeft,
  words,
  leftLabel,
  left,
  rightLabel,
  right,
  onForceStop,
}: StagePanelProps) {
  return (
    <div className="space-y-3">
      <TopicCard topic={topic} />
      <CountdownBar
        secondsLeft={secondsLeft}
        totalSeconds={totalSeconds}
        label={stage === 'stage1' ? 'Drafting' : 'Revising'}
      />
      <div className="flex items-center justify-between text-[11px] text-zinc-500">
        <span>{words} words</span>
        <button type="button" onClick={onForceStop} className="hover:text-zinc-900 dark:hover:text-zinc-100 underline">
          End early
        </button>
      </div>
      {right ? (
        <div className="grid md:grid-cols-2 gap-3">
          <Pane label={leftLabel ?? null}>{left}</Pane>
          <Pane label={rightLabel ?? null}>{right}</Pane>
        </div>
      ) : (
        <Pane label={leftLabel ?? null}>{left}</Pane>
      )}
    </div>
  );
}

function Pane({ label, children }: { label: string | null; children: React.ReactNode }) {
  return (
    <div className="space-y-1.5">
      {label && (
        <div className="text-[10px] uppercase tracking-wide font-semibold text-zinc-500">
          {label}
        </div>
      )}
      {children}
    </div>
  );
}

function TopicCard({ topic }: { topic: string }) {
  return (
    <div className="rounded-lg border border-indigo-200 dark:border-indigo-500/30 bg-indigo-50/50 dark:bg-indigo-500/10 p-3">
      <div className="text-[10px] uppercase tracking-wide font-semibold text-indigo-700 dark:text-indigo-300">
        Topic
      </div>
      <div className="mt-0.5 text-sm font-medium leading-relaxed">{topic}</div>
    </div>
  );
}

interface SetupProps {
  topic: string;
  setTopic: (s: string) => void;
  fetchTopic: () => void;
  topicLoading: boolean;
  topicError: string | null;
  configured: boolean;
  writingSeconds: number;
  revisionSeconds: number;
  setWritingSeconds: (n: number) => void;
  setRevisionSeconds: (n: number) => void;
  onStart: () => void;
}

function SetupPanel(p: SetupProps) {
  return (
    <div className="space-y-4">
      <div>
        <h2 className="text-lg font-semibold">90-second writing drill</h2>
        <p className="text-sm text-zinc-500 mt-1">
          Generate a topic, write for the chosen time, then revise. Both stages can be extended in 10/30/60s increments when time is up.
        </p>
      </div>

      <Pane label="Topic">
        <textarea
          value={p.topic}
          onChange={(e) => p.setTopic(e.target.value)}
          rows={3}
          placeholder="Click 'Generate topic' or paste your own."
          className="w-full rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-950 p-2.5 text-sm leading-relaxed resize-none focus:outline-none focus:ring-2 focus:ring-indigo-500"
        />
        <div className="flex flex-wrap gap-2 mt-2 text-xs">
          <button
            type="button"
            onClick={p.fetchTopic}
            disabled={p.topicLoading || !p.configured}
            className="px-3 py-1.5 rounded-md bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 disabled:opacity-50"
          >
            {p.topicLoading ? 'Generating…' : 'Generate topic'}
          </button>
          {!p.configured && (
            <Link to="/settings" className="px-3 py-1.5 rounded-md border border-amber-300 text-amber-700 dark:text-amber-400">
              Set API key →
            </Link>
          )}
          {p.topicError && <span className="text-red-600 dark:text-red-400 self-center">{p.topicError}</span>}
        </div>
      </Pane>

      <div className="grid grid-cols-2 gap-3">
        <Pane label="Writing seconds">
          <input
            type="number"
            min={10}
            max={600}
            value={p.writingSeconds}
            onChange={(e) => p.setWritingSeconds(parseInt(e.target.value, 10) || 90)}
            className="input"
          />
        </Pane>
        <Pane label="Revision seconds">
          <input
            type="number"
            min={30}
            max={1800}
            value={p.revisionSeconds}
            onChange={(e) => p.setRevisionSeconds(parseInt(e.target.value, 10) || 300)}
            className="input"
          />
        </Pane>
      </div>

      <button
        type="button"
        onClick={p.onStart}
        disabled={!p.topic.trim()}
        className="w-full px-4 py-2.5 rounded-md bg-indigo-600 text-white text-sm font-semibold disabled:opacity-50"
      >
        Start drafting →
      </button>
    </div>
  );
}

interface DoneProps {
  topic: string;
  stage1Draft: string;
  revision: string;
  stage1Words: number;
  stage2Words: number;
  stage1UsedSeconds: number;
  stage2UsedSeconds: number;
  stage1Extensions: number[];
  stage2Extensions: number[];
  configured: boolean;
  feedback: WritingFeedback | null;
  feedbackLoading: boolean;
  feedbackError: string | null;
  onRequestFeedback: () => void;
  onReset: () => void;
}

function DonePanel(p: DoneProps) {
  return (
    <div className="space-y-4">
      <div className="rounded-lg border border-emerald-200 dark:border-emerald-500/30 bg-emerald-50 dark:bg-emerald-500/10 p-3">
        <div className="text-sm font-semibold text-emerald-800 dark:text-emerald-300">
          ✓ Session saved
        </div>
        <div className="mt-1 text-xs text-emerald-700/80 dark:text-emerald-400/80">
          Drafted {p.stage1Words}w in {p.stage1UsedSeconds}s
          {p.stage1Extensions.length > 0 && ` (+${p.stage1Extensions.join('+')}s)`}
          {' · '}
          Revised to {p.stage2Words}w in {p.stage2UsedSeconds}s
          {p.stage2Extensions.length > 0 && ` (+${p.stage2Extensions.join('+')}s)`}.
        </div>
      </div>

      <TopicCard topic={p.topic} />

      <div className="grid md:grid-cols-2 gap-3">
        <Pane label="Original draft">
          <div className="rounded-md border border-zinc-200 dark:border-zinc-800 bg-zinc-50 dark:bg-zinc-950 p-3 text-sm whitespace-pre-wrap min-h-[160px]">
            {p.stage1Draft || <em className="text-zinc-400">empty</em>}
          </div>
        </Pane>
        <Pane label="Revision">
          <div className="rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 p-3 text-sm whitespace-pre-wrap min-h-[160px]">
            {p.revision || <em className="text-zinc-400">empty</em>}
          </div>
        </Pane>
      </div>

      {p.feedback ? (
        <WritingFeedbackPanel feedback={p.feedback} />
      ) : (
        <div className="flex flex-wrap gap-2 items-center">
          <button
            type="button"
            onClick={p.onRequestFeedback}
            disabled={p.feedbackLoading || !p.configured}
            className="px-3 py-1.5 rounded-md bg-indigo-600 text-white text-xs disabled:opacity-50"
          >
            {p.feedbackLoading ? 'Asking AI…' : 'Get AI feedback'}
          </button>
          {p.feedbackError && (
            <span className="text-xs text-red-600 dark:text-red-400">{p.feedbackError}</span>
          )}
        </div>
      )}

      <div className="flex gap-2">
        <button
          type="button"
          onClick={p.onReset}
          className="px-3 py-1.5 rounded-md border border-zinc-200 dark:border-zinc-800 text-xs"
        >
          Run another →
        </button>
        <Link to="/history" className="px-3 py-1.5 rounded-md border border-zinc-200 dark:border-zinc-800 text-xs">
          View history
        </Link>
      </div>
    </div>
  );
}

function ResumeBanner({
  draft,
  onResume,
  onDiscard,
}: {
  draft: DraftState;
  onResume: () => void;
  onDiscard: () => void;
}) {
  return (
    <div className="rounded-lg border border-amber-200 dark:border-amber-500/30 bg-amber-50 dark:bg-amber-500/10 p-4 space-y-3">
      <div className="text-sm font-semibold">Unfinished draft found</div>
      <div className="text-xs text-zinc-600 dark:text-zinc-400">
        Topic: <span className="font-medium">{draft.topic || '(none)'}</span>
        {' · '}draft {countWords(draft.stage1_draft)}w
        {draft.stage2_revision && ` · revision ${countWords(draft.stage2_revision)}w`}
      </div>
      <div className="flex gap-2">
        <button
          type="button"
          onClick={onResume}
          className="px-3 py-1.5 rounded-md bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 text-xs"
        >
          Restore into setup
        </button>
        <button
          type="button"
          onClick={onDiscard}
          className="px-3 py-1.5 rounded-md border border-zinc-200 dark:border-zinc-800 text-xs text-red-600"
        >
          Discard
        </button>
      </div>
    </div>
  );
}
