import type { WritingFeedback } from '@/lib/schema';

interface Props {
  feedback: WritingFeedback;
}

export function WritingFeedbackPanel({ feedback }: Props) {
  const empty =
    feedback.vocab_swaps.length === 0 &&
    feedback.structure_upgrades.length === 0 &&
    feedback.missing_expressions.length === 0;

  return (
    <div className="space-y-4 rounded-lg border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 p-4">
      <h3 className="text-sm font-semibold flex items-center gap-2">
        <span className="text-[10px] uppercase tracking-wider bg-indigo-100 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300 px-1.5 py-0.5 rounded">
          AI feedback
        </span>
      </h3>

      {feedback.overall && (
        <p className="text-sm text-zinc-700 dark:text-zinc-300 leading-relaxed">
          {feedback.overall}
        </p>
      )}

      {empty && (
        <p className="text-xs text-zinc-500 italic">
          No specific suggestions returned. Try writing a longer revision next time for richer feedback.
        </p>
      )}

      {feedback.vocab_swaps.length > 0 && (
        <Section label="Vocabulary swaps">
          <ul className="space-y-2">
            {feedback.vocab_swaps.map((s, i) => (
              <li key={i} className="text-xs">
                <div className="flex flex-wrap items-baseline gap-1.5">
                  <code className="px-1 py-0.5 rounded bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 line-through decoration-red-400">
                    {s.from}
                  </code>
                  <span className="text-zinc-400">→</span>
                  <code className="px-1 py-0.5 rounded bg-emerald-50 dark:bg-emerald-900/20 text-emerald-700 dark:text-emerald-300">
                    {s.to}
                  </code>
                </div>
                <div className="mt-0.5 text-zinc-500 leading-snug">{s.why}</div>
              </li>
            ))}
          </ul>
        </Section>
      )}

      {feedback.structure_upgrades.length > 0 && (
        <Section label="Structure upgrades">
          <ul className="space-y-3">
            {feedback.structure_upgrades.map((u, i) => (
              <li key={i} className="text-xs">
                <div className="rounded bg-zinc-50 dark:bg-zinc-950 border border-zinc-200 dark:border-zinc-800 p-2 line-through decoration-zinc-400">
                  {u.original}
                </div>
                <div className="mt-1.5 rounded bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 p-2 text-emerald-800 dark:text-emerald-200">
                  {u.upgraded}
                </div>
                <div className="mt-1 text-zinc-500 leading-snug">{u.why}</div>
              </li>
            ))}
          </ul>
        </Section>
      )}

      {feedback.missing_expressions.length > 0 && (
        <Section label="Missing expressions worth using">
          <ul className="flex flex-wrap gap-1.5">
            {feedback.missing_expressions.map((e, i) => (
              <li
                key={i}
                className="text-xs px-2 py-1 rounded bg-amber-50 dark:bg-amber-900/20 text-amber-800 dark:text-amber-300 border border-amber-200 dark:border-amber-800"
              >
                {e}
              </li>
            ))}
          </ul>
        </Section>
      )}
    </div>
  );
}

function Section({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="space-y-2">
      <div className="text-[10px] uppercase tracking-wide font-semibold text-zinc-500">
        {label}
      </div>
      {children}
    </div>
  );
}
