import { useEffect } from 'react';

interface Props {
  stage: 'stage1' | 'stage2';
  wordCount: number;
  onExtend: (seconds: number) => void;
  onCancel: () => void;
}

const STAGE_TITLES: Record<Props['stage'], string> = {
  stage1: 'Time up — drafting',
  stage2: 'Time up — revising',
};

const STAGE_CANCEL_LABELS: Record<Props['stage'], string> = {
  stage1: 'Cancel — proceed to revision →',
  stage2: 'Cancel — save & finish ✓',
};

const EXTENSIONS = [10, 30, 60];

export function TimeUpDialog({ stage, wordCount, onExtend, onCancel }: Props) {
  // Block clicks on background; lock focus by autofocusing the cancel button
  // so Enter advances the user without keyboard input being lost into a hidden
  // textarea behind the modal.
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        // Treat Escape as "I'm done" — the same as Cancel.
        e.preventDefault();
        onCancel();
      }
    };
    document.addEventListener('keydown', onKey, true);
    return () => document.removeEventListener('keydown', onKey, true);
  }, [onCancel]);

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center"
      aria-modal="true"
      role="dialog"
      aria-labelledby="time-up-title"
    >
      <div className="absolute inset-0 bg-black/40" />
      <div className="relative w-[min(420px,92vw)] rounded-xl bg-white dark:bg-zinc-950 shadow-2xl overflow-hidden">
        <div className="px-5 py-4 border-b border-zinc-200 dark:border-zinc-800">
          <h2 id="time-up-title" className="text-sm font-semibold">
            {STAGE_TITLES[stage]}
          </h2>
          <p className="mt-1 text-xs text-zinc-500">
            You wrote <span className="font-semibold text-zinc-700 dark:text-zinc-300">{wordCount}</span> words.
            Need more time?
          </p>
        </div>

        <div className="px-5 py-4 space-y-3">
          <div className="grid grid-cols-3 gap-2">
            {EXTENSIONS.map((sec) => (
              <button
                key={sec}
                type="button"
                onClick={() => onExtend(sec)}
                className="px-3 py-2 rounded-md bg-indigo-50 dark:bg-indigo-500/10 border border-indigo-200 dark:border-indigo-500/30 text-indigo-700 dark:text-indigo-300 text-sm font-semibold hover:bg-indigo-100 dark:hover:bg-indigo-500/20"
              >
                +{sec}s
              </button>
            ))}
          </div>
          <button
            type="button"
            onClick={onCancel}
            autoFocus
            className="w-full px-3 py-2 rounded-md bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 text-sm font-semibold"
          >
            {STAGE_CANCEL_LABELS[stage]}
          </button>
          <p className="text-[10px] text-zinc-400 text-center">
            Press <kbd className="px-1 py-0.5 bg-zinc-100 dark:bg-zinc-800 rounded">Esc</kbd> for the same as Cancel.
          </p>
        </div>
      </div>
    </div>
  );
}

export function countWords(text: string): number {
  const trimmed = text.trim();
  if (!trimmed) return 0;
  return trimmed.split(/\s+/).length;
}
