import { Link } from 'react-router-dom';
import { useEffect, useState } from 'react';
import { loadSessions } from '@/lib/storage';
import { computeStats, type SessionStats } from '@/lib/stats';
import type { Session } from '@/lib/schema';

const cards = [
  {
    to: '/write',
    title: '90s Writing',
    blurb:
      'Write under time pressure on a generated topic, then revise. Trains your reflex to use ready-made sentence stems.',
    accent: 'from-indigo-500 to-violet-500',
  },
  {
    to: '/paraphrase',
    title: 'Paraphrasing',
    blurb:
      'Rewrite one sentence three different ways. Trains the "say it another way" rescue skill in real-time conversation.',
    accent: 'from-emerald-500 to-teal-500',
  },
];

export function Home() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [stats, setStats] = useState<SessionStats | null>(null);

  useEffect(() => {
    const all = loadSessions();
    setSessions(all);
    setStats(computeStats(all));
  }, []);

  const recent = sessions.slice(-3).reverse();

  return (
    <div className="space-y-8">
      {stats && stats.total > 0 && <StatsPanel stats={stats} />}

      <section>
        <h2 className="text-lg font-semibold mb-1">Pick a drill</h2>
        <p className="text-sm text-zinc-500 mb-4">
          Short daily reps build the reflex to produce English without freezing.
        </p>
        <div className="grid sm:grid-cols-2 gap-3">
          {cards.map((c) => (
            <Link
              key={c.to}
              to={c.to}
              className="group rounded-xl border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 p-4 hover:border-zinc-400 dark:hover:border-zinc-600 transition-colors"
            >
              <div
                className={`inline-block text-[10px] uppercase tracking-wider font-semibold text-white px-2 py-0.5 rounded bg-gradient-to-r ${c.accent}`}
              >
                Drill
              </div>
              <h3 className="mt-2 text-base font-semibold">{c.title}</h3>
              <p className="mt-1 text-xs text-zinc-500 leading-relaxed">{c.blurb}</p>
              <div className="mt-3 text-xs text-indigo-600 dark:text-indigo-400 group-hover:translate-x-0.5 transition-transform">
                Start →
              </div>
            </Link>
          ))}
        </div>
      </section>

      <section>
        <h2 className="text-sm font-semibold mb-2">Recent sessions</h2>
        {recent.length === 0 ? (
          <p className="text-xs text-zinc-500">
            No sessions yet. Run a drill above and they'll show up here.
          </p>
        ) : (
          <ul className="space-y-1.5">
            {recent.map((s) => (
              <li
                key={s.id}
                className="rounded-md border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 px-3 py-2 text-xs"
              >
                <div className="flex items-center gap-2">
                  <span className="text-[10px] uppercase font-semibold text-indigo-600 dark:text-indigo-400">
                    {s.mode}
                  </span>
                  <span className="text-zinc-400">{new Date(s.created_at).toLocaleString()}</span>
                </div>
                <div className="mt-1 truncate text-zinc-700 dark:text-zinc-300">
                  {s.mode === 'write' ? s.topic : s.source}
                </div>
              </li>
            ))}
          </ul>
        )}
        <Link to="/history" className="text-xs text-indigo-600 dark:text-indigo-400 hover:underline mt-2 inline-block">
          View all →
        </Link>
      </section>
    </div>
  );
}

function StatsPanel({ stats }: { stats: SessionStats }) {
  const writePercent =
    stats.total === 0 ? 0 : Math.round((stats.writeCount / stats.total) * 100);

  return (
    <section className="grid grid-cols-2 sm:grid-cols-4 gap-2">
      <Stat label="Streak" value={stats.currentStreakDays} suffix="d" highlight={stats.currentStreakDays >= 3} />
      <Stat label="This week" value={stats.thisWeek} />
      <Stat label="Total" value={stats.total} />
      <Stat
        label="Write / Para"
        value={`${writePercent}% / ${100 - writePercent}%`}
        small
      />
    </section>
  );
}

function Stat({
  label,
  value,
  suffix,
  highlight,
  small,
}: {
  label: string;
  value: number | string;
  suffix?: string;
  highlight?: boolean;
  small?: boolean;
}) {
  return (
    <div
      className={`rounded-lg border px-3 py-2.5 ${
        highlight
          ? 'border-amber-300 dark:border-amber-500/40 bg-amber-50 dark:bg-amber-500/10'
          : 'border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900'
      }`}
    >
      <div className="text-[10px] uppercase tracking-wide text-zinc-500 font-semibold">
        {label}
      </div>
      <div className={`mt-0.5 font-semibold ${small ? 'text-sm' : 'text-2xl'}`}>
        {value}
        {suffix && <span className="text-xs ml-0.5 text-zinc-400">{suffix}</span>}
      </div>
    </div>
  );
}
