import type {
  ParaphraseFeedback,
  Settings,
  WritingFeedback,
} from '../schema';

export interface TopicPrefs {
  domain: 'hci' | 'general';
  categories: string[];
}

export interface AiProvider {
  readonly id: 'openai' | 'anthropic' | 'azure';
  generateWritingTopic(prefs: TopicPrefs): Promise<string>;
  generateParaphraseSource(prefs: TopicPrefs): Promise<string>;
  writingFeedback(args: {
    topic: string;
    draft: string;
    revised: string;
  }): Promise<WritingFeedback>;
  paraphraseFeedback(args: {
    source: string;
    rewrites: string[];
  }): Promise<ParaphraseFeedback>;
}

export class AiNotConfiguredError extends Error {
  constructor(provider: string) {
    super(`${provider} API key not set. Configure it in Settings.`);
    this.name = 'AiNotConfiguredError';
  }
}

export class AiCallError extends Error {
  status: number | null;
  constructor(message: string, status: number | null = null) {
    super(message);
    this.name = 'AiCallError';
    this.status = status;
  }
}

// Defaults refreshed 2026-04-25 to current top-of-line models.
// "Topic" = small/fast (one-sentence output, cheap is fine).
// "Feedback" = capable model (structured JSON, nuanced critique).
export const DEFAULT_OPENAI_TOPIC_MODEL = 'gpt-5.4-nano';
export const DEFAULT_OPENAI_FEEDBACK_MODEL = 'gpt-5.5';
export const DEFAULT_ANTHROPIC_TOPIC_MODEL = 'claude-haiku-4-5-20251001';
export const DEFAULT_ANTHROPIC_FEEDBACK_MODEL = 'claude-opus-4-7';
export const DEFAULT_AZURE_TOPIC_MODEL = 'gpt-5.4-nano';
export const DEFAULT_AZURE_FEEDBACK_MODEL = 'gpt-5.5';

export function resolveTopicModel(settings: Settings): string {
  if (settings.model_topic) return settings.model_topic;
  switch (settings.provider) {
    case 'openai':
      return DEFAULT_OPENAI_TOPIC_MODEL;
    case 'anthropic':
      return DEFAULT_ANTHROPIC_TOPIC_MODEL;
    case 'azure':
      return DEFAULT_AZURE_TOPIC_MODEL;
  }
}

export function resolveFeedbackModel(settings: Settings): string {
  if (settings.model_feedback) return settings.model_feedback;
  switch (settings.provider) {
    case 'openai':
      return DEFAULT_OPENAI_FEEDBACK_MODEL;
    case 'anthropic':
      return DEFAULT_ANTHROPIC_FEEDBACK_MODEL;
    case 'azure':
      return DEFAULT_AZURE_FEEDBACK_MODEL;
  }
}
