import { NavLink, Outlet } from 'react-router-dom';
import { useSettings } from '@/lib/store';
import { isProviderConfigured } from '@/lib/ai/factory';

const navItems = [
  { to: '/', label: 'Home', end: true },
  { to: '/write', label: 'Write' },
  { to: '/paraphrase', label: 'Paraphrase' },
  { to: '/history', label: 'History' },
  { to: '/settings', label: 'Settings' },
];

export function Layout() {
  const settings = useSettings((s) => s.settings);
  const configured = isProviderConfigured(settings);

  return (
    <div className="min-h-full flex flex-col">
      <header className="border-b border-zinc-200 dark:border-zinc-800 bg-white/80 dark:bg-zinc-950/80 backdrop-blur sticky top-0 z-10">
        <div className="max-w-3xl mx-auto px-4 py-3 flex items-center gap-4">
          <h1 className="text-sm font-semibold tracking-tight">
            English Output Pal
          </h1>
          <nav className="flex gap-1 text-xs">
            {navItems.map((n) => (
              <NavLink
                key={n.to}
                to={n.to}
                end={n.end}
                className={({ isActive }) =>
                  `px-2.5 py-1 rounded-md transition-colors ${
                    isActive
                      ? 'bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900'
                      : 'text-zinc-600 dark:text-zinc-400 hover:bg-zinc-100 dark:hover:bg-zinc-800'
                  }`
                }
              >
                {n.label}
              </NavLink>
            ))}
          </nav>
          <div className="ml-auto text-[10px]">
            {configured ? (
              <span className="text-emerald-600 dark:text-emerald-400">
                ● {settings.provider}
              </span>
            ) : (
              <NavLink
                to="/settings"
                className="text-amber-600 dark:text-amber-400 hover:underline"
              >
                ● API key not set
              </NavLink>
            )}
          </div>
        </div>
      </header>
      <main className="flex-1 max-w-3xl w-full mx-auto px-4 py-6">
        <Outlet />
      </main>
    </div>
  );
}
