import type { Settings } from '../schema';
import type { AiProvider } from './provider';
import { OpenAiProvider } from './openai';
import { AnthropicProvider } from './anthropic';
import { AzureProvider } from './azure';

export function getProvider(settings: Settings): AiProvider {
  switch (settings.provider) {
    case 'anthropic':
      return new AnthropicProvider(settings);
    case 'azure':
      return new AzureProvider(settings);
    case 'openai':
      return new OpenAiProvider(settings);
  }
}

export function isProviderConfigured(settings: Settings): boolean {
  switch (settings.provider) {
    case 'openai':
      return !!settings.openai_api_key.trim();
    case 'anthropic':
      return !!settings.anthropic_api_key.trim();
    case 'azure':
      return (
        !!settings.azure_api_key.trim() && !!settings.azure_endpoint.trim()
      );
  }
}
