import type { TopicPrefs } from './provider';

function domainLine(prefs: TopicPrefs): string {
  return prefs.domain === 'hci'
    ? 'The learner is an HCI / CS PhD student practicing academic and professional English.'
    : 'The learner is practicing general academic and professional English.';
}

function categoryLine(prefs: TopicPrefs): string {
  if (prefs.categories.length === 0) return '';
  return `Preferred categories: ${prefs.categories.join(', ')}.`;
}

export const TOPIC_WRITING_SYSTEM = `You are a coach for a non-native English speaker doing timed writing drills. Generate exactly ONE writing prompt per request.

Constraints:
- 1 sentence, 8-18 words.
- Specific enough to answer in 3-5 sentences within 90 seconds.
- No multi-part prompts. No "and explain..." chains.
- Do NOT wrap in quotes. Output ONLY the prompt.`;

export function topicWritingUserMessage(prefs: TopicPrefs): string {
  return [
    domainLine(prefs),
    categoryLine(prefs),
    'Sample categories you can rotate through: research methods, paper writing, conference Q&A, technical explanation, lab/group work.',
    'Generate one prompt now.',
  ]
    .filter(Boolean)
    .join('\n');
}

export const TOPIC_PARAPHRASE_SYSTEM = `You generate ONE English sentence per request, suitable for paraphrasing practice.

Constraints:
- 12-22 words.
- Moderate complexity: at least one verb-noun collocation or one adjective-noun collocation worth rewriting.
- Topic relevant to academic / research / professional life when possible.
- The meaning should be clearly preservable across multiple rewrites.
- Output ONLY the sentence. No quotes, no preamble.`;

export function topicParaphraseUserMessage(prefs: TopicPrefs): string {
  return [
    domainLine(prefs),
    categoryLine(prefs),
    'Generate one sentence now.',
  ]
    .filter(Boolean)
    .join('\n');
}

export const WRITING_FEEDBACK_SYSTEM = `You are an English writing coach. The learner did a 90-second timed draft and a 5-minute revision. Your job is to identify concrete, high-value improvements they can apply next time.

Output STRICT JSON (no markdown, no commentary) matching this schema:
{
  "vocab_swaps": [{"from": "...", "to": "...", "why": "..."}],
  "structure_upgrades": [{"original": "...", "upgraded": "...", "why": "..."}],
  "missing_expressions": ["...", "..."],
  "overall": "1-2 sentences of high-level feedback."
}

Rules:
- vocab_swaps: 3-5 entries; pick word/phrase upgrades that make the writing more idiomatic. "from" must literally appear in the revision.
- structure_upgrades: 1-2 entries; rewrite a full clause or sentence with a stronger structure (e.g., from passive to active, from generic to a known sentence stem). "original" must be a literal substring of the revision.
- missing_expressions: 2-3 sentence stems / collocations the learner SHOULD have used given the topic but didn't.
- Keep "why" under 15 words each.
- If the revision is too short to assess, return empty arrays and use "overall" to explain.`;

export function writingFeedbackUserMessage(args: {
  topic: string;
  draft: string;
  revised: string;
}): string {
  return [
    `Topic: ${args.topic}`,
    '',
    '90-second first draft:',
    args.draft || '(empty)',
    '',
    '5-minute revision:',
    args.revised || '(empty)',
    '',
    'Return JSON only.',
  ].join('\n');
}

export const PARAPHRASE_FEEDBACK_SYSTEM = `You evaluate paraphrase practice. Given a source sentence and 3 rewrites, score each one and judge collective diversity.

Output STRICT JSON (no markdown, no commentary):
{
  "per_rewrite": [
    {"fidelity": "ok"|"partial"|"broken", "naturalness": 1..5, "comment": "<= 20 words"}
  ],
  "diversity_score": 1..5,
  "reference_paraphrases": ["...", "..."],
  "overall": "1-2 sentences."
}

Rules:
- per_rewrite must have exactly 3 items, in the same order as input.
- fidelity: "ok" = preserves meaning; "partial" = drifts in nuance; "broken" = changes the meaning.
- naturalness: 5 = native-fluent; 1 = unnatural/wrong.
- diversity_score: 5 if the three rewrites use distinct structures; 1 if they are near-duplicates.
- reference_paraphrases: 2 alternative rewrites you would suggest, demonstrably different in structure from each other and from the user's three.`;

export function paraphraseFeedbackUserMessage(args: {
  source: string;
  rewrites: string[];
}): string {
  const lines = [`Source: ${args.source}`, ''];
  args.rewrites.forEach((r, i) => {
    lines.push(`Rewrite ${i + 1}: ${r || '(empty)'}`);
  });
  lines.push('', 'Return JSON only.');
  return lines.join('\n');
}
