import { formatSeconds } from '@/lib/useCountdown';

interface Props {
  secondsLeft: number;
  totalSeconds: number;
  label: string;
}

export function CountdownBar({ secondsLeft, totalSeconds, label }: Props) {
  const ratio = totalSeconds === 0 ? 0 : Math.max(0, Math.min(1, secondsLeft / totalSeconds));
  const tone =
    ratio > 0.4
      ? 'bg-emerald-500'
      : ratio > 0.15
        ? 'bg-amber-500'
        : 'bg-red-500';

  return (
    <div className="space-y-1">
      <div className="flex items-center justify-between text-[11px]">
        <span className="text-zinc-500 uppercase tracking-wide font-semibold">
          {label}
        </span>
        <span className="font-mono tabular-nums text-zinc-700 dark:text-zinc-300">
          {formatSeconds(secondsLeft)}
        </span>
      </div>
      <div className="h-1.5 rounded-full bg-zinc-200 dark:bg-zinc-800 overflow-hidden">
        <div
          className={`h-full ${tone} transition-[width] duration-100 ease-linear`}
          style={{ width: `${ratio * 100}%` }}
        />
      </div>
    </div>
  );
}
