import { useEffect, useState } from 'react';

interface UseCountdown {
  secondsLeft: number;
  isRunning: boolean;
  expired: boolean;
  start: (seconds: number) => void;
  addSeconds: (seconds: number) => void;
  stop: () => void;
}

/**
 * Headless countdown driven by an end-time timestamp. Re-renders ~10/sec while
 * running, stops ticking when expired so we don't waste cycles. The parent
 * derives `expired` from the hook's return and reacts to it (e.g., shows a
 * blocking dialog).
 */
export function useCountdown(): UseCountdown {
  const [endTime, setEndTime] = useState<number | null>(null);
  const [now, setNow] = useState<number>(Date.now());

  useEffect(() => {
    if (endTime === null) return;
    if (now >= endTime) return;
    const id = setTimeout(() => setNow(Date.now()), 100);
    return () => clearTimeout(id);
  }, [endTime, now]);

  const isRunning = endTime !== null && now < endTime;
  const expired = endTime !== null && now >= endTime;
  const secondsLeft =
    endTime === null ? 0 : Math.max(0, (endTime - now) / 1000);

  return {
    secondsLeft,
    isRunning,
    expired,
    start: (seconds: number) => {
      const t = Date.now();
      setNow(t);
      setEndTime(t + seconds * 1000);
    },
    addSeconds: (seconds: number) => {
      setEndTime((e) => (e === null ? Date.now() + seconds * 1000 : e + seconds * 1000));
    },
    stop: () => setEndTime(null),
  };
}

export function formatSeconds(s: number): string {
  const total = Math.max(0, Math.ceil(s));
  const m = Math.floor(total / 60);
  const sec = total % 60;
  return `${m}:${sec.toString().padStart(2, '0')}`;
}
