import { useEffect, useMemo, useRef, useState } from 'react';
import { Link } from 'react-router-dom';
import { deleteSession, loadSessions, saveSessions } from '@/lib/storage';
import { SessionsArraySchema } from '@/lib/schema';
import type { ParaphraseSession, Session, WriteSession } from '@/lib/schema';
import { WritingFeedbackPanel } from '@/components/WritingFeedbackPanel';
import { ParaphraseFeedbackPanel } from '@/components/ParaphraseFeedbackPanel';

type FilterMode = 'all' | 'write' | 'paraphrase';

export function History() {
  const [sessions, setSessions] = useState<Session[]>([]);
  const [filter, setFilter] = useState<FilterMode>('all');
  const [expanded, setExpanded] = useState<string | null>(null);
  const [importStatus, setImportStatus] = useState<{
    state: 'idle' | 'ok' | 'err';
    message?: string;
  }>({ state: 'idle' });
  const fileInputRef = useRef<HTMLInputElement | null>(null);

  useEffect(() => {
    setSessions(loadSessions());
  }, []);

  const sorted = useMemo(
    () => [...sessions].sort((a, b) => b.created_at.localeCompare(a.created_at)),
    [sessions]
  );

  const filtered = useMemo(
    () => (filter === 'all' ? sorted : sorted.filter((s) => s.mode === filter)),
    [sorted, filter]
  );

  const grouped = useMemo(() => groupByDay(filtered), [filtered]);

  function handleDelete(id: string) {
    if (!confirm('Delete this session permanently?')) return;
    setSessions(deleteSession(id));
    if (expanded === id) setExpanded(null);
  }

  function handleClearAll() {
    if (!confirm(`Delete ALL ${sessions.length} sessions? This cannot be undone.`)) return;
    saveSessions([]);
    setSessions([]);
    setExpanded(null);
  }

  function handleExport() {
    const blob = new Blob([JSON.stringify(sessions, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `english-output-pal_sessions_${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 0);
  }

  async function handleImportFile(file: File) {
    setImportStatus({ state: 'idle' });
    try {
      const text = await file.text();
      const incoming = SessionsArraySchema.parse(JSON.parse(text));
      const existing = loadSessions();
      const existingIds = new Set(existing.map((s) => s.id));
      const fresh = incoming.filter((s) => !existingIds.has(s.id));
      const merged = [...existing, ...fresh];
      saveSessions(merged);
      setSessions(merged);
      setImportStatus({
        state: 'ok',
        message: `Imported ${fresh.length} new (${incoming.length - fresh.length} duplicates skipped).`,
      });
    } catch (err) {
      setImportStatus({
        state: 'err',
        message: `Import failed: ${err instanceof Error ? err.message : String(err)}`,
      });
    }
  }

  return (
    <div className="space-y-5">
      <div className="flex items-center justify-between gap-2 flex-wrap">
        <h2 className="text-lg font-semibold">History</h2>
        <div className="flex gap-2 text-xs">
          <input
            ref={fileInputRef}
            type="file"
            accept="application/json,.json"
            className="hidden"
            onChange={(e) => {
              const f = e.target.files?.[0];
              if (f) handleImportFile(f);
              e.target.value = '';
            }}
          />
          <button
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="px-3 py-1.5 rounded-md border border-zinc-200 dark:border-zinc-800"
          >
            Import JSON
          </button>
          <button
            type="button"
            onClick={handleExport}
            disabled={sessions.length === 0}
            className="px-3 py-1.5 rounded-md border border-zinc-200 dark:border-zinc-800 disabled:opacity-50"
          >
            Export JSON
          </button>
          <button
            type="button"
            onClick={handleClearAll}
            disabled={sessions.length === 0}
            className="px-3 py-1.5 rounded-md border border-red-200 dark:border-red-800 text-red-600 disabled:opacity-50"
          >
            Clear all
          </button>
        </div>
      </div>

      {importStatus.message && (
        <div
          className={`text-xs ${
            importStatus.state === 'err'
              ? 'text-red-600 dark:text-red-400'
              : 'text-emerald-700 dark:text-emerald-400'
          }`}
        >
          {importStatus.message}
        </div>
      )}

      <div className="flex gap-1.5">
        {(['all', 'write', 'paraphrase'] as FilterMode[]).map((f) => (
          <button
            key={f}
            type="button"
            onClick={() => setFilter(f)}
            className={`px-2.5 py-1 rounded-md text-xs border ${
              filter === f
                ? 'bg-zinc-900 dark:bg-zinc-100 text-white dark:text-zinc-900 border-transparent'
                : 'bg-white dark:bg-zinc-900 border-zinc-200 dark:border-zinc-800'
            }`}
          >
            {f === 'all' ? 'All' : f === 'write' ? 'Writing' : 'Paraphrase'}
            {f !== 'all' && (
              <span className="ml-1 opacity-60">
                ({sorted.filter((s) => s.mode === f).length})
              </span>
            )}
          </button>
        ))}
        <span className="ml-auto text-xs text-zinc-500 self-center">{filtered.length} sessions</span>
      </div>

      {filtered.length === 0 ? (
        <p className="text-xs text-zinc-500 py-12 text-center">
          No sessions yet. Run a{' '}
          <Link to="/write" className="text-indigo-600 dark:text-indigo-400 hover:underline">
            writing
          </Link>{' '}
          or{' '}
          <Link to="/paraphrase" className="text-indigo-600 dark:text-indigo-400 hover:underline">
            paraphrase
          </Link>{' '}
          drill to populate this list.
        </p>
      ) : (
        <div className="space-y-5">
          {grouped.map(({ day, items }) => (
            <section key={day} className="space-y-2">
              <h3 className="text-xs uppercase tracking-wide font-semibold text-zinc-500">
                {day}
              </h3>
              <ul className="space-y-2">
                {items.map((s) => (
                  <SessionCard
                    key={s.id}
                    session={s}
                    expanded={expanded === s.id}
                    onToggle={() => setExpanded((cur) => (cur === s.id ? null : s.id))}
                    onDelete={() => handleDelete(s.id)}
                  />
                ))}
              </ul>
            </section>
          ))}
        </div>
      )}
    </div>
  );
}

function groupByDay(sessions: Session[]): Array<{ day: string; items: Session[] }> {
  const groups = new Map<string, Session[]>();
  for (const s of sessions) {
    const day = new Date(s.created_at).toLocaleDateString(undefined, {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
    const arr = groups.get(day) ?? [];
    arr.push(s);
    groups.set(day, arr);
  }
  return [...groups.entries()].map(([day, items]) => ({ day, items }));
}

function SessionCard({
  session,
  expanded,
  onToggle,
  onDelete,
}: {
  session: Session;
  expanded: boolean;
  onToggle: () => void;
  onDelete: () => void;
}) {
  const time = new Date(session.created_at).toLocaleTimeString(undefined, {
    hour: '2-digit',
    minute: '2-digit',
  });
  const modeColor =
    session.mode === 'write'
      ? 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/40 dark:text-indigo-300'
      : 'bg-emerald-100 text-emerald-700 dark:bg-emerald-900/40 dark:text-emerald-300';

  return (
    <li className="rounded-lg border border-zinc-200 dark:border-zinc-800 bg-white dark:bg-zinc-900 overflow-hidden">
      <button
        type="button"
        onClick={onToggle}
        className="w-full flex items-start gap-3 px-3 py-2.5 text-left hover:bg-zinc-50 dark:hover:bg-zinc-800/50 transition-colors"
      >
        <span className={`text-[10px] uppercase font-semibold px-1.5 py-0.5 rounded shrink-0 ${modeColor}`}>
          {session.mode}
        </span>
        <div className="flex-1 min-w-0">
          <div className="text-sm truncate">
            {session.mode === 'write' ? session.topic : session.source}
          </div>
          <div className="text-[11px] text-zinc-500 mt-0.5">
            {time}
            {session.mode === 'write' && (
              <>
                {' · '}
                {countWords(session.stage1_draft)}w → {countWords(session.stage2_revision)}w
              </>
            )}
          </div>
        </div>
        <span className="text-xs text-zinc-400 shrink-0">{expanded ? '▾' : '▸'}</span>
      </button>

      {expanded && (
        <div className="border-t border-zinc-200 dark:border-zinc-800 px-3 py-3 space-y-3">
          {session.mode === 'write' ? (
            <WriteSessionDetail session={session} />
          ) : (
            <ParaphraseSessionDetail session={session} />
          )}
          <div className="flex justify-end">
            <button
              type="button"
              onClick={onDelete}
              className="text-[11px] text-red-600 hover:underline"
            >
              Delete session
            </button>
          </div>
        </div>
      )}
    </li>
  );
}

function WriteSessionDetail({ session }: { session: WriteSession }) {
  return (
    <div className="space-y-3">
      <Stat>
        <Block label="Original draft">
          <pre className="whitespace-pre-wrap text-sm leading-relaxed bg-zinc-50 dark:bg-zinc-950 rounded-md p-2.5 border border-zinc-200 dark:border-zinc-800">
            {session.stage1_draft || <em className="text-zinc-400">empty</em>}
          </pre>
        </Block>
        <Block label="Revision">
          <pre className="whitespace-pre-wrap text-sm leading-relaxed bg-zinc-50 dark:bg-zinc-950 rounded-md p-2.5 border border-zinc-200 dark:border-zinc-800">
            {session.stage2_revision || <em className="text-zinc-400">empty</em>}
          </pre>
        </Block>
      </Stat>
      <div className="text-[11px] text-zinc-500">
        Drafted in {session.stage1_used_seconds}s
        {session.stage1_extensions.length > 0 && ` (+${session.stage1_extensions.join('+')}s)`}
        {' · '}Revised in {session.stage2_used_seconds}s
        {session.stage2_extensions.length > 0 && ` (+${session.stage2_extensions.join('+')}s)`}
      </div>
      {session.feedback && <WritingFeedbackPanel feedback={session.feedback} />}
    </div>
  );
}

function ParaphraseSessionDetail({ session }: { session: ParaphraseSession }) {
  return (
    <div className="space-y-3">
      <Block label="Source">
        <div className="text-sm bg-zinc-50 dark:bg-zinc-950 rounded-md p-2.5 border border-zinc-200 dark:border-zinc-800">
          {session.source}
        </div>
      </Block>
      <Block label="Rewrites">
        <ol className="space-y-1.5 text-sm list-decimal list-inside">
          {session.rewrites.map((r, i) => (
            <li key={i} className="bg-zinc-50 dark:bg-zinc-950 rounded-md p-2 border border-zinc-200 dark:border-zinc-800">
              {r || <em className="text-zinc-400">empty</em>}
            </li>
          ))}
        </ol>
      </Block>
      {session.feedback && <ParaphraseFeedbackPanel feedback={session.feedback} rewrites={session.rewrites} />}
    </div>
  );
}

function Stat({ children }: { children: React.ReactNode }) {
  return <div className="grid md:grid-cols-2 gap-3">{children}</div>;
}

function Block({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div className="space-y-1">
      <div className="text-[10px] uppercase tracking-wide font-semibold text-zinc-500">
        {label}
      </div>
      {children}
    </div>
  );
}

function countWords(text: string): number {
  const trimmed = text.trim();
  if (!trimmed) return 0;
  return trimmed.split(/\s+/).length;
}
