import { SessionsArraySchema, SettingsSchema, type Session, type Settings } from './schema';

const SETTINGS_KEY = 'eop_settings';
const SESSIONS_KEY = 'eop_sessions';
const DRAFT_KEY = 'eop_draft_in_progress';

export function loadSettings(): Settings {
  const raw = localStorage.getItem(SETTINGS_KEY);
  if (!raw) return SettingsSchema.parse({});
  try {
    return SettingsSchema.parse(JSON.parse(raw));
  } catch (err) {
    console.warn('[EOP] settings parse failed, resetting:', err);
    return SettingsSchema.parse({});
  }
}

export function saveSettings(settings: Settings): void {
  localStorage.setItem(SETTINGS_KEY, JSON.stringify(settings));
}

export function loadSessions(): Session[] {
  const raw = localStorage.getItem(SESSIONS_KEY);
  if (!raw) return [];
  try {
    return SessionsArraySchema.parse(JSON.parse(raw));
  } catch (err) {
    console.warn('[EOP] sessions parse failed:', err);
    return [];
  }
}

export function saveSessions(sessions: Session[]): void {
  localStorage.setItem(SESSIONS_KEY, JSON.stringify(sessions));
}

export function appendSession(session: Session): Session[] {
  const all = loadSessions();
  all.push(session);
  saveSessions(all);
  return all;
}

export function updateSession(id: string, patch: Partial<Session>): Session[] {
  const all = loadSessions();
  const idx = all.findIndex((s) => s.id === id);
  if (idx === -1) throw new Error(`Session ${id} not found`);
  // Type-narrowing-safe shallow merge: patch must be compatible with the
  // discriminated mode of the existing session.
  all[idx] = { ...all[idx], ...patch } as Session;
  saveSessions(all);
  return all;
}

export function deleteSession(id: string): Session[] {
  const all = loadSessions().filter((s) => s.id !== id);
  saveSessions(all);
  return all;
}

export type DraftSnapshot = {
  mode: 'write' | 'paraphrase';
  data: unknown;
  saved_at: string;
};

export function saveDraft(snapshot: DraftSnapshot): void {
  localStorage.setItem(DRAFT_KEY, JSON.stringify(snapshot));
}

export function loadDraft(): DraftSnapshot | null {
  const raw = localStorage.getItem(DRAFT_KEY);
  if (!raw) return null;
  try {
    return JSON.parse(raw) as DraftSnapshot;
  } catch {
    return null;
  }
}

export function clearDraft(): void {
  localStorage.removeItem(DRAFT_KEY);
}

export function newId(prefix: string): string {
  const ts = new Date()
    .toISOString()
    .replace(/[:.]/g, '-')
    .replace('T', '_')
    .slice(0, 19);
  const rand = Math.random().toString(36).slice(2, 6);
  return `${prefix}_${ts}_${rand}`;
}
