import {
  AiCallError,
  AiNotConfiguredError,
  resolveFeedbackModel,
  resolveTopicModel,
  type AiProvider,
  type TopicPrefs,
} from './provider';
import {
  PARAPHRASE_FEEDBACK_SYSTEM,
  TOPIC_PARAPHRASE_SYSTEM,
  TOPIC_WRITING_SYSTEM,
  WRITING_FEEDBACK_SYSTEM,
  paraphraseFeedbackUserMessage,
  topicParaphraseUserMessage,
  topicWritingUserMessage,
  writingFeedbackUserMessage,
} from './prompts';
import {
  ParaphraseFeedbackSchema,
  WritingFeedbackSchema,
  type ParaphraseFeedback,
  type Settings,
  type WritingFeedback,
} from '../schema';
import { parseJsonLoose } from './json';
import { createLogger, preview } from '../logger';

const log = createLogger('azure');

interface ChatArgs {
  model: string;
  system: string;
  user: string;
  temperature?: number;
  jsonMode?: boolean;
}

/**
 * Targets the Azure AI Inference REST API (the unified Foundry endpoint that
 * exposes OpenAI / Llama / Phi / DeepSeek / Mistral / etc. via a single
 * OpenAI-compatible chat-completions route).
 *
 * Endpoint shapes the user can paste into settings.azure_endpoint:
 *   - Foundry hub:        https://<project>.services.ai.azure.com/models
 *   - Azure OpenAI:       https://<resource>.openai.azure.com/openai/deployments/<deployment>
 *   - Serverless model:   https://<deployment>.<region>.models.ai.azure.com/v1
 *
 * In all three, we POST to `${endpoint}/chat/completions?api-version=...`.
 * For Foundry hub the request body's `model` field selects the deployed model;
 * for the other two the deployment is in the URL but Azure still requires a
 * non-empty `model` field, so we pass through whatever the user configured.
 */
export class AzureProvider implements AiProvider {
  readonly id = 'azure' as const;
  private apiKey: string;
  private endpoint: string;
  private apiVersion: string;
  private settings: Settings;

  constructor(settings: Settings) {
    this.settings = settings;
    this.apiKey = settings.azure_api_key.trim();
    this.endpoint = settings.azure_endpoint.trim().replace(/\/+$/, '');
    this.apiVersion = settings.azure_api_version.trim() || '2024-08-01-preview';
  }

  private async chat({
    model,
    system,
    user,
    temperature = 0.8,
    jsonMode = false,
  }: ChatArgs): Promise<string> {
    if (!this.apiKey) throw new AiNotConfiguredError('Azure');
    if (!this.endpoint)
      throw new AiNotConfiguredError('Azure (missing endpoint URL)');

    const url = `${this.endpoint}/chat/completions?api-version=${encodeURIComponent(this.apiVersion)}`;
    const body: Record<string, unknown> = {
      model,
      messages: [
        { role: 'system', content: system },
        { role: 'user', content: user },
      ],
      temperature,
    };
    if (jsonMode) body.response_format = { type: 'json_object' };

    log.debug('chat →', {
      url,
      model,
      jsonMode,
      userLen: user.length,
      userPreview: preview(user),
    });
    const t0 = performance.now();

    let response: Response;
    try {
      response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'api-key': this.apiKey,
        },
        body: JSON.stringify(body),
      });
    } catch (err) {
      log.error('network error', err);
      throw new AiCallError(
        `Network error calling Azure: ${err instanceof Error ? err.message : String(err)}`
      );
    }
    if (!response.ok) {
      const text = await response.text().catch(() => '');
      log.error('http error', { status: response.status, body: text.slice(0, 200) });
      throw new AiCallError(
        `Azure ${response.status}: ${text.slice(0, 200)}`,
        response.status
      );
    }
    const data = (await response.json()) as {
      choices?: Array<{ message?: { content?: string } }>;
      usage?: { prompt_tokens?: number; completion_tokens?: number };
    };
    const content = data.choices?.[0]?.message?.content?.trim() ?? '';
    log.debug('chat ←', {
      durationMs: Math.round(performance.now() - t0),
      contentLen: content.length,
      contentPreview: preview(content),
      tokens: data.usage,
    });
    if (!content) throw new AiCallError('Azure returned empty content');
    return content;
  }

  async generateWritingTopic(prefs: TopicPrefs): Promise<string> {
    return this.chat({
      model: resolveTopicModel(this.settings),
      system: TOPIC_WRITING_SYSTEM,
      user: topicWritingUserMessage(prefs),
    });
  }

  async generateParaphraseSource(prefs: TopicPrefs): Promise<string> {
    return this.chat({
      model: resolveTopicModel(this.settings),
      system: TOPIC_PARAPHRASE_SYSTEM,
      user: topicParaphraseUserMessage(prefs),
    });
  }

  async writingFeedback(args: {
    topic: string;
    draft: string;
    revised: string;
  }): Promise<WritingFeedback> {
    const raw = await this.chat({
      model: resolveFeedbackModel(this.settings),
      system: WRITING_FEEDBACK_SYSTEM,
      user: writingFeedbackUserMessage(args),
      temperature: 0.4,
      jsonMode: true,
    });
    return WritingFeedbackSchema.parse(parseJsonLoose(raw));
  }

  async paraphraseFeedback(args: {
    source: string;
    rewrites: string[];
  }): Promise<ParaphraseFeedback> {
    const raw = await this.chat({
      model: resolveFeedbackModel(this.settings),
      system: PARAPHRASE_FEEDBACK_SYSTEM,
      user: paraphraseFeedbackUserMessage(args),
      temperature: 0.4,
      jsonMode: true,
    });
    return ParaphraseFeedbackSchema.parse(parseJsonLoose(raw));
  }
}
