import { z } from 'zod';

export const ProviderIdSchema = z.enum(['openai', 'anthropic', 'azure']);
export type ProviderId = z.infer<typeof ProviderIdSchema>;

export const SettingsSchema = z.object({
  provider: ProviderIdSchema.default('openai'),
  openai_api_key: z.string().default(''),
  anthropic_api_key: z.string().default(''),
  azure_api_key: z.string().default(''),
  azure_endpoint: z.string().default(''),
  azure_api_version: z.string().default('2024-08-01-preview'),
  model_topic: z.string().default(''),
  model_feedback: z.string().default(''),
  verbose: z.boolean().default(false),
  prefs: z
    .object({
      domain: z.enum(['hci', 'general']).default('hci'),
      categories: z.array(z.string()).default([]),
      writing_seconds: z.number().int().positive().default(90),
      revision_seconds: z.number().int().positive().default(300),
    })
    .default({
      domain: 'hci',
      categories: [],
      writing_seconds: 90,
      revision_seconds: 300,
    }),
});
export type Settings = z.infer<typeof SettingsSchema>;

export const WritingFeedbackSchema = z.object({
  vocab_swaps: z
    .array(z.object({ from: z.string(), to: z.string(), why: z.string() }))
    .default([]),
  structure_upgrades: z
    .array(z.object({ original: z.string(), upgraded: z.string(), why: z.string() }))
    .default([]),
  missing_expressions: z.array(z.string()).default([]),
  overall: z.string().default(''),
});
export type WritingFeedback = z.infer<typeof WritingFeedbackSchema>;

export const ParaphraseFeedbackItemSchema = z.object({
  fidelity: z.enum(['ok', 'partial', 'broken']),
  naturalness: z.number().int().min(1).max(5),
  comment: z.string(),
});
export const ParaphraseFeedbackSchema = z.object({
  per_rewrite: z.array(ParaphraseFeedbackItemSchema),
  diversity_score: z.number().int().min(1).max(5),
  reference_paraphrases: z.array(z.string()).default([]),
  overall: z.string().default(''),
});
export type ParaphraseFeedback = z.infer<typeof ParaphraseFeedbackSchema>;

export const WriteSessionSchema = z.object({
  id: z.string(),
  mode: z.literal('write'),
  created_at: z.string(),
  topic: z.string(),
  stage1_draft: z.string(),
  stage1_target_seconds: z.number().int().nonnegative(),
  stage1_used_seconds: z.number().int().nonnegative(),
  stage1_extensions: z.array(z.number().int()).default([]),
  stage2_revision: z.string().default(''),
  stage2_target_seconds: z.number().int().nonnegative(),
  stage2_used_seconds: z.number().int().nonnegative(),
  stage2_extensions: z.array(z.number().int()).default([]),
  feedback: WritingFeedbackSchema.optional(),
});
export type WriteSession = z.infer<typeof WriteSessionSchema>;

export const ParaphraseSessionSchema = z.object({
  id: z.string(),
  mode: z.literal('paraphrase'),
  created_at: z.string(),
  source: z.string(),
  rewrites: z.array(z.string()).length(3),
  feedback: ParaphraseFeedbackSchema.optional(),
});
export type ParaphraseSession = z.infer<typeof ParaphraseSessionSchema>;

export const SessionSchema = z.discriminatedUnion('mode', [
  WriteSessionSchema,
  ParaphraseSessionSchema,
]);
export type Session = z.infer<typeof SessionSchema>;

export const SessionsArraySchema = z.array(SessionSchema);
